THE CLAIM:
{
 "title": "Year-1 may hit a building lull the trend growth hides",
 "narrative": "The model assumes Year-1 lands in an average demand year at 1% of the serviceable market. But EMEA capacity under construction has stalled at about 2.5 GW while the pipeline grew 25% to nearly 15 GW, so projects are stuck in planning. If 2026 is a digestion year, Year-1 order pace could be roughly half the assumed level.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "EMEA construction stalled at 2.5 GW; pipeline grew to 15 GW",
   "refs": [
    "digest:geo-NL#c3",
    "digest:geo-NL#c2"
   ]
  },
  {
   "step": "propagation",
   "text": "Cloud buys 61% of demand; a pause stalls orders",
   "refs": [
    "digest:geo-DE#c18",
    "ledger:shape.cagr"
   ]
  },
  {
   "step": "model-impact",
   "text": "A trough year roughly halves achievable Year-1 pace",
   "refs": [
    "ledger:obtainableFactor"
   ]
  }
 ],
 "falsifier": "Cushman & Wakefield or JLL H1-2026 prints showing under-construction capacity above 2.5 GW with rising starts, or hyperscaler guidance re-accelerating 2026 European data-center capex.",
 "category": "exogenous",
 "evidence": [
  {
   "title": "Cushman & Wakefield: European data centre growth is shifting",
   "sourceType": "industry-report",
   "publisher": "Cushman & Wakefield",
   "date": "2026-04-28",
   "excerpt": "the total development pipeline increased by more than 25% to nearly 15 GW. In practice, however, delivery is lagging behind. Capacity currently under construction has plateaued at around 2.5 GW.",
   "url": "https://www.cushmanwakefield.com/en/netherlands/news/2026/04/emea-datacentre-update-h2-2025",
   "attached": true
  },
  {
   "title": "1Q 2026 EMEA Data Center Market Report",
   "sourceType": "industry-report",
   "publisher": "datacenterHawk",
   "date": null,
   "excerpt": "Hyperscalers returned to Europe at record scale... 767MW Q1 absorption (record)",
   "url": "https://datacenterhawk.com/resources/market-insights/1q-2026-emea-data-center-market-report",
   "attached": true
  },
  {
   "title": "EMEA year end data centre report 2025",
   "sourceType": "industry-report",
   "publisher": "JLL",
   "date": "2026-03-30",
   "excerpt": "FLAP-D vacancy hits record low of 6.3%, pipeline is 83% pre-let. Capacity is being absorbed faster than it can be replaced.",
   "url": "https://www.jll.com/en-uk/insights/emea-data-centre-report",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "obtainableFactor",
  "label": "Year-1 obtainable share of SAM",
  "kind": "assumption",
  "value": 0.01,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.005,
   "high": 0.03
  },
  "funnelActive": true,
  "derivation": {
   "method": "Benchmark anchoring",
   "expression": "Prospeo assigns 1% of SAM to YEAR 1 (3% and 5% are Years 2–3) — the prior 3% read the Year-2 figure as Year 1. Corrected to 1%; the Tractian comparable (first-year ~$1.2M against a multi-$B market) sits below 1%.",
   "crossCheck": "Early-procurement mechanism (DC electrical gear locked 12–24mo before fit-out) independently supports ≤2%; open 2026 EU rack-PDU tenders keep 2–3% inside the band."
  },
  "provenance": {
   "rationale": "Refinement cycle 1 caught the benchmark-period misread — the value now follows the source's own Year-1 figure, band 0.5–3%.",
   "promotionPath": "Replace with pipeline-based model once first CE deals close (win-rate × cycle time × capacity)."
  },
  "evidence": [
   {
    "title": "Addressable markets — SOM benchmarks",
    "sourceType": "analyst-estimate",
    "publisher": "Prospeo",
    "date": null,
    "excerpt": "SOM benchmarks that won't get you laughed out of the room: 1% of SAM in Year 1, 3% in Year 2, 5% in Year 3.",
    "attached": true
   },
   {
    "title": "Serviceable Obtainable Market (SOM) — early-stage ranges",
    "sourceType": "analyst-estimate",
    "publisher": "IdeaPlan",
    "date": "2024",
    "excerpt": "For early-stage companies, SOM is typically 1-5% of SAM. For growing companies with product-market fit, SOM can reach 10-20% of SAM.",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
